function e(){document.documentElement.setAttribute("data-bs-theme","dark"),localStorage.setItem("theme","dark")}e();const r=new MutationObserver(()=>{document.documentElement.getAttribute("data-bs-theme")!=="dark"&&e()});r.observe(document.documentElement,{attributes:!0,attributeFilter:["data-bs-theme"]});window.addEventListener("load",()=>{e(),document.querySelectorAll(".theme-switch").forEach(t=>{t.remove()})});
